const actionItem = ($json.action_items || '').trim();
const manager = $json['Manager'] || '';
const firstName = $json['First Name'] || '';
const lastName = $json['Last Name'] || '';
const role = $json['Role'] || '';
const startDate = $json['Start Date'] || '';

let dueDate = '';
let phase = '30';
try {
  const start = new Date(startDate);
  if (/90.day/i.test(actionItem)) {
    phase = '90';
    const d = new Date(start);
    d.setDate(d.getDate() + 90);
    dueDate = d.toISOString().split('T')[0];
  } else if (/60.day/i.test(actionItem)) {
    phase = '60';
    const d = new Date(start);
    d.setDate(d.getDate() + 60);
    dueDate = d.toISOString().split('T')[0];
  } else {
    const d = new Date(start);
    d.setDate(d.getDate() + 30);
    dueDate = d.toISOString().split('T')[0];
  }
} catch(e) {
  dueDate = '';
}

return {
  json: {
    task_title: manager + ' — ' + actionItem,
    task_notes: 'New Hire: ' + firstName + ' ' + lastName + ' (' + role + '). Phase: ' + phase + ' days.',
    due_date: dueDate
  }
};
